import React from "react";

const TestimonialCard = ({ testimonial }) => {
  // destructuring con valores por defecto
  const {
    text = "I replaced coffee with a healthy alternative that keeps me energized all day long, without any crashes or jitters.",
  } = testimonial || {};

  return (
    <div
      style={{
        width: "320px",
        minHeight: "300px",
        backgroundColor: "#154734",
        borderRadius: "10px",
        boxShadow: "0 2px 8px rgba(0,0,0,0.3)",
        padding: "2rem",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        textAlign: "center",
        color: "#e4d0a9",
      }}
    >
      <div style={{ marginBottom: "1.5rem", fontWeight: "bold", fontSize: "1.3rem" }}>
        Frontend
      </div>

      <p style={{ marginBottom: "1rem", fontSize: "1rem", lineHeight: "1.5" }}>
        "{text}"
      </p>

      {/* Agregado nombre "Kristi" un poco más abajo */}
      <div style={{ marginTop: "auto", marginBottom: "0.2rem", fontWeight: "600", fontSize: "1rem" }}>
        Kristi
      </div>

      {/* Palabra "Productor" debajo del nombre */}
      <div style={{ fontSize: "0.9rem", fontWeight: "400", opacity: 0.8 }}>
        Productor
      </div>
    </div>
  );
};

export default TestimonialCard;
